UPDATE chat_room_member
SET hidden_at = CURRENT_TIMESTAMP(6)
WHERE room_id = #{roomId}
  AND member_id = #{memberId}
  AND deleted_yn = 'N'

UPDATE chat_room_member
SET left_at = CURRENT_TIMESTAMP(6),
    is_active = 0
WHERE room_id = #{roomId}
  AND member_id = #{memberId}
  AND deleted_yn = 'N'

UPDATE chat_room_member
SET last_read_message_id =
        CASE
            WHEN last_read_message_id IS NULL THEN #{lastReadMessageId}
            WHEN last_read_message_id < #{lastReadMessageId} THEN #{lastReadMessageId}
            ELSE last_read_message_id
        END,
    last_read_at = CURRENT_TIMESTAMP(6)
WHERE room_id = #{roomId}
  AND member_id = #{memberId}
  AND deleted_yn = 'N'

UPDATE chat_room_member
SET last_read_at = CURRENT_TIMESTAMP(6)
WHERE room_id = #{roomId}
  AND member_id = #{memberId}
  AND deleted_yn = 'N'

mapper.select:
SELECT r.room_id AS roomId, r.room_type AS roomType, r.room_name AS roomName, r.room_description AS roomDescription, r.created_by AS createdBy, DATE_FORMAT(r.created_at, '%Y-%m-%dT%H:%i:%s') AS createdAt, r.deleted_yn AS deletedYn, COALESCE(mc.member_count, 0) AS memberCount, latest.last_message AS lastMessage, latest.last_message_at AS lastMessageAt, 0 AS unreadCount FROM chat_room r JOIN chat_room_member rm ON rm.room_id = r.room_id AND rm.deleted_yn = 'N' LEFT JOIN ( SELECT room_id, COUNT(*) AS member_count FROM chat_room_member WHERE deleted_yn = 'N' AND left_at IS NULL AND is_active = 1 GROUP BY room_id ) mc ON mc.room_id = r.room_id LEFT JOIN ( SELECT room_id, DATE_FORMAT(MAX(created_at), '%Y-%m-%dT%H:%i:%s') AS last_message_at, SUBSTRING_INDEX( GROUP_CONCAT(content ORDER BY created_at DESC, message_id DESC SEPARATOR '|||'), '|||', 1 ) AS last_message FROM chat_message WHERE deleted_yn = 'N' GROUP BY room_id ) latest ON latest.room_id = r.room_id WHERE r.deleted_yn = 'N'
AND r.room_type = #{roomType}
GROUP BY r.room_id, r.room_type, r.room_name, r.room_description, r.created_by, r.created_at, r.deleted_yn, mc.member_count, latest.last_message, latest.last_message_at HAVING COUNT(DISTINCT rm.member_id) = #{memberCount} AND SUM( CASE WHEN rm.member_id IN
#{memberId}
THEN 1 ELSE 0 END ) = #{memberCount} LIMIT 1

SELECT r.room_id AS roomId, r.room_type AS roomType, r.room_name AS roomName, r.room_description AS roomDescription, r.created_by AS createdBy, DATE_FORMAT(r.created_at, '%Y-%m-%dT%H:%i:%s') AS createdAt, r.deleted_yn AS deletedYn, COALESCE(mc.member_count, 0) AS memberCount, latest.last_message AS lastMessage, latest.last_message_at AS lastMessageAt, COALESCE(unread.unread_count, 0) AS unreadCount FROM chat_room r JOIN chat_room_member rm ON rm.room_id = r.room_id AND rm.member_id = #{memberId} AND rm.deleted_yn = 'N'
AND r.room_type = #{roomType}
LEFT JOIN ( SELECT room_id, COUNT(*) AS member_count FROM chat_room_member WHERE deleted_yn = 'N' AND left_at IS NULL AND is_active = 1 GROUP BY room_id ) mc ON mc.room_id = r.room_id LEFT JOIN ( SELECT cm.room_id, DATE_FORMAT(MAX(cm.created_at), '%Y-%m-%dT%H:%i:%s') AS last_message_at, SUBSTRING_INDEX( GROUP_CONCAT(cm.content ORDER BY cm.created_at DESC, cm.message_id DESC SEPARATOR '|||'), '|||', 1 ) AS last_message FROM chat_message cm JOIN chat_room_member visible_rm ON visible_rm.room_id = cm.room_id AND visible_rm.member_id = #{memberId} AND visible_rm.deleted_yn = 'N' WHERE cm.deleted_yn = 'N' AND visible_rm.left_at IS NULL AND visible_rm.is_active = 1 AND (visible_rm.joined_at IS NULL OR cm.created_at >= visible_rm.joined_at) AND (visible_rm.hidden_at IS NULL OR cm.created_at > visible_rm.hidden_at) GROUP BY cm.room_id ) latest ON latest.room_id = r.room_id LEFT JOIN ( SELECT cm.room_id, COUNT(*) AS unread_count FROM chat_message cm JOIN chat_room_member reader ON reader.room_id = cm.room_id AND reader.member_id = #{memberId} AND reader.deleted_yn = 'N' WHERE cm.deleted_yn = 'N' AND cm.sender_id <> #{memberId} AND reader.left_at IS NULL AND reader.is_active = 1 AND (reader.joined_at IS NULL OR cm.created_at >= reader.joined_at) AND (reader.hidden_at IS NULL OR cm.created_at > reader.hidden_at) AND (reader.last_read_message_id IS NULL OR cm.message_id > reader.last_read_message_id) GROUP BY cm.room_id ) unread ON unread.room_id = r.room_id WHERE r.deleted_yn = 'N' AND rm.left_at IS NULL AND rm.is_active = 1 AND ( rm.hidden_at IS NULL OR EXISTS ( SELECT 1 FROM chat_message recent WHERE recent.room_id = r.room_id AND recent.deleted_yn = 'N' AND recent.created_at > rm.hidden_at ) ) ORDER BY CASE WHEN latest.last_message_at IS NULL THEN 1 ELSE 0 END, latest.last_message_at DESC, r.room_id DESC
